import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"氢能赛道 2026——政策拐点与订单验证","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"电力新能源/氢能/_深化_2026-06-16_氢能2026拐点.md","filePath":"电力新能源/氢能/_深化_2026-06-16_氢能2026拐点.md","lastUpdated":1782226922000}'),l={name:"电力新能源/氢能/_深化_2026-06-16_氢能2026拐点.md"};function i(h,t,o,n,u,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="氢能赛道-2026——政策拐点与订单验证" tabindex="-1">氢能赛道 2026——政策拐点与订单验证 <a class="header-anchor" href="#氢能赛道-2026——政策拐点与订单验证" aria-label="Permalink to &quot;氢能赛道 2026——政策拐点与订单验证&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>2026 年是氢能从示范期走向商业化的拐点之年。十五五规划首列氢能为&quot;未来产业&quot;，2026 年政府工作报告定位为&quot;新增长点&quot;。三部门氢能综合应用试点单个城市群奖补上限 16 亿元。全国绿氢建成产能 25 万吨/年（较 2024 翻番），在建超 100 万吨/年。电解槽 1-4 月订单 382MW，海外出口同比 +120%。但设备端已现产能过剩苗头，2027 年将进高峰。</p><h2 id="政策面" tabindex="-1">政策面 <a class="header-anchor" href="#政策面" aria-label="Permalink to &quot;政策面&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间</th><th>政策</th><th>要点</th></tr></thead><tbody><tr><td>2026 年</td><td>十五五规划纲要</td><td>氢能列为&quot;未来产业&quot;</td></tr><tr><td>2026.3</td><td>政府工作报告</td><td>首次定位氢能为&quot;新增长点&quot;，绿色燃料首次写入</td></tr><tr><td>2026.3</td><td>三部门氢能综合应用试点通知</td><td>单个城市群 4 年奖补上限 16 亿元</td></tr><tr><td>2025</td><td>《能源法》施行</td><td>氢与煤/油/气/风/光并列法定能源</td></tr></tbody></table><h3 id="三部门试点核心" tabindex="-1">三部门试点核心 <a class="header-anchor" href="#三部门试点核心" aria-label="Permalink to &quot;三部门试点核心&quot;">​</a></h3><ul><li>申报截止：2026 年 4 月 15 日</li><li>四个工业场景：合成甲醇、合成氨、炼化、煤化工</li><li>从&quot;补贴车&quot;转向&quot;补贴用&quot;——工业消纳取代交通成为主战场</li><li>目标：2030 年终端用氢均价降至 25 元/kg 以下</li></ul><h2 id="产能与订单" tabindex="-1">产能与订单 <a class="header-anchor" href="#产能与订单" aria-label="Permalink to &quot;产能与订单&quot;">​</a></h2><h3 id="绿氢产能" tabindex="-1">绿氢产能 <a class="header-anchor" href="#绿氢产能" aria-label="Permalink to &quot;绿氢产能&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间</th><th>建成产能</th><th>在建产能</th></tr></thead><tbody><tr><td>2024 年底</td><td>~12 万吨/年</td><td>-</td></tr><tr><td>2025 年底</td><td>~25 万吨/年</td><td>~80 万吨/年</td></tr><tr><td>2026.3</td><td>超 25 万吨/年</td><td>超 100 万吨/年</td></tr></tbody></table><h3 id="电解槽订单-2026-年-1-4-月" tabindex="-1">电解槽订单（2026 年 1-4 月） <a class="header-anchor" href="#电解槽订单-2026-年-1-4-月" aria-label="Permalink to &quot;电解槽订单（2026 年 1-4 月）&quot;">​</a></h3><p>总规模：382.625MW</p><table tabindex="0"><thead><tr><th>排名</th><th>企业</th><th>订单规模</th><th>市占率</th></tr></thead><tbody><tr><td>1</td><td>隆基氢能</td><td>90 MW</td><td>23.5%</td></tr><tr><td>2</td><td>航天工程</td><td>80 MW</td><td>20.9%</td></tr><tr><td>3</td><td>阳光氢能</td><td>60 MW</td><td>15.7%</td></tr><tr><td>4</td><td>上海电气</td><td>50 MW</td><td>13.1%</td></tr><tr><td>5</td><td>青骐骥</td><td>40 MW</td><td>10.5%</td></tr><tr><td>-</td><td>前五合计</td><td>320 MW</td><td>83.6%</td></tr></tbody></table><p><strong>技术路线</strong>：碱性 93% &gt; PEM 6.5% &gt; AEM 0.5%（碱性仍为绝对主力）</p><h3 id="海外出口" tabindex="-1">海外出口 <a class="header-anchor" href="#海外出口" aria-label="Permalink to &quot;海外出口&quot;">​</a></h3><ul><li>电解槽出口同比 +120%</li><li>国富氢能在手 5.6 亿元，海外订单占比 28%，预计年底升至 35%-40%</li><li>厚普股份海外收入增速超 300%（西班牙订单，欧洲 TUV 认证）</li><li>沙特 ACWA Power 签约、印度液氢出口推进</li><li>未来核心增量市场：沙特、欧洲、印度</li></ul><h2 id="应用结构转型" tabindex="-1">应用结构转型 <a class="header-anchor" href="#应用结构转型" aria-label="Permalink to &quot;应用结构转型&quot;">​</a></h2><p>从&quot;交通为主&quot;转向&quot;工业为主&quot;：</p><table tabindex="0"><thead><tr><th>应用领域</th><th>占比</th><th>说明</th></tr></thead><tbody><tr><td>合成氨</td><td>27%</td><td>绿氨替代灰氨</td></tr><tr><td>合成甲醇</td><td>26%</td><td>航运燃料需求爆发</td></tr><tr><td>炼化</td><td>16%</td><td>绿氢替代天然气制氢</td></tr><tr><td>煤化工</td><td>11%</td><td>降碳改造</td></tr><tr><td>交通</td><td>&lt;20%</td><td>燃料电池车</td></tr></tbody></table><p><strong>标志项目</strong>：</p><ul><li>沈阳 50 万吨级风光制氢绿色醇油项目（总投资 320 亿元，2GW 风电）- 国内首个 50 万吨级</li><li>内蒙古赤峰远景 152 万吨绿色氢氨项目首期 32 万吨已投产（全球最大）</li><li>新疆库车绿氢 2 万吨/年，光伏制氢直供塔河炼化</li></ul><h2 id="经济性" tabindex="-1">经济性 <a class="header-anchor" href="#经济性" aria-label="Permalink to &quot;经济性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产品</th><th>绿色成本</th><th>灰色成本</th><th>绿色溢价</th></tr></thead><tbody><tr><td>绿氨</td><td>6000-8000 元/吨</td><td>3000-4000 元/吨</td><td>~100%</td></tr><tr><td>绿醇</td><td>3500-4500 元/吨</td><td>1500-1800 元/吨</td><td>~140%</td></tr><tr><td>绿氢</td><td>16 元/kg (电价 0.19 元/度)</td><td>10-12 元/kg</td><td>~40%</td></tr></tbody></table><p>华泰证券测算：0.19 元/度电下绿氢成本 16 元/kg，平价节奏： 氢化工（制绿氨）&gt; 氢工业供热 &gt; 氢燃料电池 &gt; 船用甲醇 &gt; 航空 SAF &gt; 氢冶金</p><h2 id="拐点特征" tabindex="-1">拐点特征 <a class="header-anchor" href="#拐点特征" aria-label="Permalink to &quot;拐点特征&quot;">​</a></h2><ul><li>政策从&quot;鼓励&quot;升级为&quot;强制&quot;（试点+配额）</li><li>订单集中、规模巨大（百亿级项目密集上马）</li><li>出口爆发（海外订单 +120%）</li><li>工业消纳打开天花板（交通仅 &lt;20%，工业近 80%）</li><li>但：设备端已现产能过剩苗头，2027 年进高峰</li><li>拐点特征：量升价跌、订单集中、头部受益、淘汰加速</li></ul><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li>电解槽产能过剩：2027 年进高峰，中小企业面临出清</li><li>绿氢仍无成本优势：绿色溢价 40%-140%，碳价（~80 元/吨）撑不起缺口</li><li>商业模式未形成：&quot;产得出、用不掉&quot;的结构性矛盾仍存</li><li>储运瓶颈：氢气储运成本高昂是规模化最大障碍</li><li>政策依赖：当前 90%+ 项目仍依赖补贴和政策驱动</li></ol><hr><p><em>来源：华泰证券、经济观察网、财联社、新华网、钛媒体、碳索氢能网</em><em>更新：2026-06-16</em></p>',30)])])}const _=d(l,[["render",i]]);export{q as __pageData,_ as default};
